<template>
    <div class="home">
        <div class="container flex">
            <div style="width:80%;">什么都没有!!!</div>
            <div class="randomGirl">
                <div class="media">
                    <a class="media-content" @click="getRandomGirl()" title="点我试试" target="_blank" :style="{backgroundImage: 'url('+randomGirl+')'}">
                        <span class="overlay"></span>
                    </a>
                    <div class="media-overlay">
                        <div class="flex">
                            <span class="day">{{ date.day }}</span>
                            <time class="year">{{ date.month }}月, {{ date.year }}</time>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import { mapState } from 'vuex';
export default {
    data(){
        return{
            randomGirl: '',
            date: {
                year: '',
                month: '',
                day: ''
            }
        }
    },
    computed: {
        ...mapState({
            device: state => state.app.device
        })
    },
    mounted() {
        this.getRandomGirl();
        this.getNowTime();
    },
    methods: {
        getNowTime(){
            var date = new Date();
            this.date.year = date.getFullYear();
            this.date.month = date.getMonth()+1;
            this.date.day = date.getDate();
        },
        getRandomGirl(){
            this.axios.get(this.gankUrl+'/api/v2/random/category/Girl/type/Girl/count/1').then((res) => {
                console.log(res);
                
                if(res.data.data){
                    this.randomGirl = res.data.data[0].url;
                }
            })
        }
    }
}
</script>
<style lang="scss" scoped>
.home{
    position: relative;
    width: 100%;
    .container{
        position: relative;
        width: 80%;
        margin: 0 auto;
    }
    .randomGirl{
        position: relative;
        background: #fff;
        border-radius: 3px;
        overflow: hidden;
        @include font_color($font-color-light);
        display: flex;
        flex-direction: column;
        word-wrap: break-word;
        width: 322px;
        .media{
            position: relative;
            display: block;
            overflow: hidden;
            border-radius: 3px;
            align-items: flex-start;
            flex-shrink: 0;
            .media-content{
                position: absolute;
                top: 0;
                bottom: 0;
                left: 0;
                right: 0;
                border: 0;
                cursor: pointer;
                border-radius: inherit;
                background-size: cover;
                background-repeat: no-repeat;
                background-position: 50% 50%;
                background-color: rgba(120, 120, 120, 0.1);
                color: #ffffff;
                .overlay{
                    width: 100%;
                    height: 100%;
                    background-color: rgba(0, 0, 0, 0.66);
                    position: absolute;
                    opacity: .22;
                    top: 0;
                    left: 0;
                    transition: opacity 0.3s ease-in-out;
                }
            }
            .media-overlay{
                position: absolute;
                top: 0;
                left: 0;
                right: 0;
                bottom: 0;
                padding: 0;
                z-index: 2;
                display: flex;
                bottom: auto;
                padding: 1.5rem;
                .flex{
                    font-family: nicetheme, Arial, sans-serif;
                    flex-direction: column;
                    .day{
                        color: #fff;
                        font-size: 3.5rem;
                        font-weight: 300;
                        line-height: 1;
                    }
                    .year{
                        font-size: 0.75rem;
                        color: #fff;
                        text-align: center;
                    }
                }
            }
            &::after{
                content: '';
                display: block;
                padding-top: 100%;
            }
        }
    }
}
</style>


